// Health is the resolver for the health field.
func (r *queryResolver) Health(ctx context.Context) (*HealthStatus, error) {
	initStatus := handler.GetInitStatus()
	now := time.Now()
	uptime := now.Sub(initStatus.Started).Round(time.Second).String()

	status := "healthy"
	message := "Service is running"

	var (
		dbHealth  *DatabaseHealth
		dbErrText *string
	)
	if r.ServerDB != nil {
		start := time.Now()
		err := r.ServerDB.PingContext(ctx)
		latency := int(time.Since(start).Milliseconds())
		dbHealth = &DatabaseHealth{
			Status:  "ok",
			Latency: &latency,
		}
		if err != nil {
			status = "unhealthy"
			message = "Database connectivity check failed"
			errText := err.Error()
			dbErrText = &errText
			dbHealth.Status = "error"
			dbHealth.Error = dbErrText
		}
	}

	if status == "healthy" && !handler.IsInitialized() {
		status = "initializing"
		message = "Services are still initializing"
	}

	var mem runtime.MemStats
	runtime.ReadMemStats(&mem)
	memoryHealth := &MemoryHealth{
		Used:       float64(mem.Alloc),
		Total:      float64(mem.Sys),
		Percentage: 0,
	}
	if mem.Sys > 0 {
		memoryHealth.Percentage = (float64(mem.Alloc) / float64(mem.Sys)) * 100
	}

	return &HealthStatus{
		Status:   status,
		Message:  &message,
		Database: dbHealth,
		Memory:   memoryHealth,
		LocationDatabases: &LocationDatabasesHealth{
			Countries: &LocationDBStatus{Loaded: initStatus.Countries},
			Cities:    &LocationDBStatus{Loaded: initStatus.Cities},
		},
		Uptime:    uptime,
		Timestamp: now,
	}, nil
}

// Weather is the resolver for the weather field.
func (r *queryResolver) Weather(ctx context.Context, location *string, lat *float64, lon *float64) (*Weather, error) {
	if r.WeatherService == nil {
		return nil, fmt.Errorf("weather service not initialized")
	}

	// Validate inputs
	if (location == nil || *location == "") && (lat == nil || lon == nil) {
		return nil, fmt.Errorf("either location name or coordinates (lat/lon) must be provided")
	}

	// Get coordinates from location or use provided lat/lon
	var latitude, longitude float64
	var locationName, country, timezone string

	if lat != nil && lon != nil {
		// Use provided coordinates
		latitude = *lat
		longitude = *lon
		// Reverse geocode to get location name
		coords, err := r.WeatherService.ReverseGeocode(latitude, longitude)
		if err == nil && coords != nil {
			locationName = coords.Name
			country = coords.Country
			timezone = coords.Timezone
		} else {
			locationName = fmt.Sprintf("%.4f, %.4f", latitude, longitude)
			country = "Unknown"
		}
	} else if location != nil && *location != "" {
		// Geocode location name to coordinates
		coords, err := r.WeatherService.GetCoordinates(*location, "")
		if err != nil {
			return nil, fmt.Errorf("could not find location: %s", *location)
		}
		latitude = coords.Latitude
		longitude = coords.Longitude
		locationName = coords.Name
		country = coords.Country
		timezone = coords.Timezone
	}

	// Get current weather
	current, err := r.WeatherService.GetCurrentWeather(latitude, longitude, "imperial")
	if err != nil {
		return nil, fmt.Errorf("failed to get weather: %w", err)
	}

	// Build response
	feelsLike := current.FeelsLike
	pressure := current.Pressure
	precipitation := current.Precipitation
	cloudCover := current.CloudCover

	return &Weather{
		Location: &Location{
			Name:     locationName,
			Country:  country,
			Lat:      latitude,
			Lon:      longitude,
			Timezone: &timezone,
		},
		Current: &CurrentWeather{
			Temperature:   current.Temperature,
			FeelsLike:     &feelsLike,
			Humidity:      current.Humidity,
			Pressure:      &pressure,
			WindSpeed:     current.WindSpeed,
			Precipitation: &precipitation,
			CloudCover:    &cloudCover,
			Condition: &WeatherCondition{
				Text: r.WeatherService.GetWeatherDescription(current.WeatherCode),
				Icon: stringPtr(r.WeatherService.GetWeatherIcon(current.WeatherCode, current.IsDay == 1)),
			},
			LastUpdated: time.Now(),
		},
		Timestamp: time.Now(),
	}, nil
}

// Forecast is the resolver for the forecast field.
func (r *queryResolver) Forecast(ctx context.Context, location *string, lat *float64, lon *float64, days *int) (*Weather, error) {
	if r.WeatherService == nil {
		return nil, fmt.Errorf("weather service not initialized")
	}

	// Validate inputs
	if (location == nil || *location == "") && (lat == nil || lon == nil) {
		return nil, fmt.Errorf("either location name or coordinates (lat/lon) must be provided")
	}

	// Default to 7 days if not specified
	numDays := 7
	if days != nil && *days > 0 && *days <= 16 {
		numDays = *days
	}

	// Get coordinates from location or use provided lat/lon
	var latitude, longitude float64
	var locationName, country, timezone string

	if lat != nil && lon != nil {
		// Use provided coordinates
		latitude = *lat
		longitude = *lon
		// Reverse geocode to get location name
		coords, err := r.WeatherService.ReverseGeocode(latitude, longitude)
		if err == nil && coords != nil {
			locationName = coords.Name
			country = coords.Country
			timezone = coords.Timezone
		} else {
			locationName = fmt.Sprintf("%.4f, %.4f", latitude, longitude)
			country = "Unknown"
		}
	} else if location != nil && *location != "" {
		// Geocode location name to coordinates
		coords, err := r.WeatherService.GetCoordinates(*location, "")
		if err != nil {
			return nil, fmt.Errorf("could not find location: %s", *location)
		}
		latitude = coords.Latitude
		longitude = coords.Longitude
		locationName = coords.Name
		country = coords.Country
		timezone = coords.Timezone
	}

	// Get forecast
	forecast, err := r.WeatherService.GetForecast(latitude, longitude, numDays, "imperial")
	if err != nil {
		return nil, fmt.Errorf("failed to get forecast: %w", err)
	}

	// Convert forecast days to GraphQL type
	var forecastDays []*ForecastDay
	for _, day := range forecast.Days {
		precipitation := day.Precipitation
		chanceOfRain := day.PrecipitationProbability
		forecastDays = append(forecastDays, &ForecastDay{
			Date: day.Date,
			Day: &DayForecast{
				MaxTemp:            day.TempMax,
				MinTemp:            day.TempMin,
				TotalPrecipitation: &precipitation,
				ChanceOfRain:       &chanceOfRain,
				Condition: &WeatherCondition{
					Text: r.WeatherService.GetWeatherDescription(day.WeatherCode),
					Icon: stringPtr(r.WeatherService.GetWeatherIcon(day.WeatherCode, true)),
				},
			},
		})
	}

	return &Weather{
		Location: &Location{
			Name:     locationName,
			Country:  country,
			Lat:      latitude,
			Lon:      longitude,
			Timezone: &timezone,
		},
		Forecast:  forecastDays,
		Timestamp: time.Now(),
	}, nil
}

// SearchLocations is the resolver for the searchLocations field.
func (r *queryResolver) SearchLocations(ctx context.Context, query string) ([]*LocationSearchResult, error) {
	if r.WeatherService == nil {
		return nil, fmt.Errorf("weather service not initialized")
	}

	if query == "" {
		return []*LocationSearchResult{}, nil
	}

	// Search using WeatherService (limit to 10 results)
	locations, err := r.WeatherService.SearchLocations(query, 10)
	if err != nil {
		return nil, fmt.Errorf("location search failed: %w", err)
	}

	// Convert to GraphQL type
	results := make([]*LocationSearchResult, 0, len(locations))
	for _, loc := range locations {
		region := loc.Admin1 // Use admin1 as region
		results = append(results, &LocationSearchResult{
			Name:    loc.Name,
			Region:  &region,
			Country: loc.Country,
			Lat:     loc.Latitude,
			Lon:     loc.Longitude,
		})
	}

	return results, nil
}

