func getGraphQLCurrentAdminID(ctx context.Context) (int64, error) {
	value := ctx.Value("admin_id")
	switch id := value.(type) {
	case int:
		if id > 0 {
			return int64(id), nil
		}
	case int64:
		if id > 0 {
			return id, nil
		}
	case string:
		parsed, err := strconv.ParseInt(id, 10, 64)
		if err == nil && parsed > 0 {
			return parsed, nil
		}
	}

	return 0, fmt.Errorf("unauthorized: admin session required")
}

